typedef enum SDL_AssertState
{
 SDL_ASSERTION_RETRY, /**< تشير هذه القيمة إلى أن SDL تعيد تنفيذ عبارة التأكيد الحالية فورًا بدل متابعة التنفيذ أو إنهاء البرنامج. */
 SDL_ASSERTION_BREAK, /**< تشير هذه القيمة إلى أن SDL تطلب من المصحح التوقف عند عبارة التأكيد الحالية عبر نقطة توقف. */
 SDL_ASSERTION_ABORT, /**< تشير هذه القيمة إلى أن SDL تنهي البرنامج عند معالجة عبارة التأكيد الحالية. */
 SDL_ASSERTION_IGNORE, /**< تشير هذه القيمة إلى أن SDL تتجاهل عبارة التأكيد الحالية مرة واحدة ثم تتابع التنفيذ. */
 SDL_ASSERTION_ALWAYS_IGNORE /**< تشير هذه القيمة إلى أن SDL تتجاهل عبارة التأكيد الحالية في المرات اللاحقة أيضًا ولا تعيد طرحها من جديد. */
} SDL_AssertState;
